func TestDiffCartSnapshots(t *testing.T) {
	tests := []struct {
		name         string
		from         []store.CartSnapshotItem
		to           []store.CartSnapshotItem
		wantAdded    int
		wantRemoved  int
		wantQtyChg   int
		wantPriceChg int
	}{
		{
			name:        "empty to empty",
			from:        []store.CartSnapshotItem{},
			to:          []store.CartSnapshotItem{},
			wantAdded:   0,
			wantRemoved: 0,
		},
		{
			name:      "item added",
			from:      []store.CartSnapshotItem{},
			to:        []store.CartSnapshotItem{{ID: "1", Name: "Arroz", Qty: 2, Price: 9.99}},
			wantAdded: 1,
		},
		{
			name:        "item removed",
			from:        []store.CartSnapshotItem{{ID: "1", Name: "Arroz", Qty: 2, Price: 9.99}},
			to:          []store.CartSnapshotItem{},
			wantRemoved: 1,
		},
		{
			name:       "quantity changed",
			from:       []store.CartSnapshotItem{{ID: "1", Name: "Arroz", Qty: 2, Price: 9.99}},
			to:         []store.CartSnapshotItem{{ID: "1", Name: "Arroz", Qty: 4, Price: 9.99}},
			wantQtyChg: 1,
		},
		{
			name:         "price changed",
			from:         []store.CartSnapshotItem{{ID: "1", Name: "Arroz", Qty: 2, Price: 9.99}},
			to:           []store.CartSnapshotItem{{ID: "1", Name: "Arroz", Qty: 2, Price: 11.99}},
			wantPriceChg: 1,
		},
		{
			name: "no change",
			from: []store.CartSnapshotItem{{ID: "1", Name: "Arroz", Qty: 2, Price: 9.99}},
			to:   []store.CartSnapshotItem{{ID: "1", Name: "Arroz", Qty: 2, Price: 9.99}},
		},
		{
			name: "mixed changes",
			from: []store.CartSnapshotItem{
				{ID: "1", Name: "Arroz", Qty: 2, Price: 9.99},
				{ID: "2", Name: "Feijao", Qty: 1, Price: 5.99},
			},
			to: []store.CartSnapshotItem{
				{ID: "1", Name: "Arroz", Qty: 4, Price: 9.99},
				{ID: "3", Name: "Macarrao", Qty: 1, Price: 3.99},
			},
			wantAdded:   1, // Macarrao
			wantRemoved: 1, // Feijao
			wantQtyChg:  1, // Arroz qty 2→4
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			result := diffCartSnapshots(tc.from, tc.to)
			if len(result.Added) != tc.wantAdded {
				t.Errorf("added: got %d, want %d", len(result.Added), tc.wantAdded)
			}
			if len(result.Removed) != tc.wantRemoved {
				t.Errorf("removed: got %d, want %d", len(result.Removed), tc.wantRemoved)
			}
			if len(result.QuantityChanged) != tc.wantQtyChg {
				t.Errorf("qty_changed: got %d, want %d", len(result.QuantityChanged), tc.wantQtyChg)
			}
			if len(result.PriceChanged) != tc.wantPriceChg {
				t.Errorf("price_changed: got %d, want %d", len(result.PriceChanged), tc.wantPriceChg)
			}
		})
	}
}

func TestExtractCartItems(t *testing.T) {
	tests := []struct {
		name      string
		data      string
		wantCount int
	}{
		{
			name:      "items key",
			data:      `{"items":[{"id":"1","name":"Arroz","qty":2,"price":9.99}]}`,
			wantCount: 1,
		},
		{
			name:      "empty items",
			data:      `{"items":[]}`,
			wantCount: 0,
		},
		{
			name:      "no id field skipped",
			data:      `{"items":[{"name":"Arroz","qty":2}]}`,
			wantCount: 0,
		},
		{
			name:      "numeric id",
			data:      `{"items":[{"id":123,"name":"Arroz","qty":2,"price":9.99}]}`,
			wantCount: 1,
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			items := extractCartItems(json.RawMessage(tc.data))
			if len(items) != tc.wantCount {
				t.Errorf("got %d items, want %d", len(items), tc.wantCount)
			}
		})
	}
}
